from flask import Flask, request, jsonify
import os
import json
import time

app = Flask(__name__)
CACHE_FILE = 'cache.json'
CACHE_EXPIRATION = 300  # seconds

def load_cache():
    if os.path.exists(CACHE_FILE):
        with open(CACHE_FILE, 'r') as f:
            return json.load(f)
    return {}

def save_cache(cache):
    with open(CACHE_FILE, 'w') as f:
        json.dump(cache, f)

def get_cached_response(key):
    cache = load_cache()
    if key in cache:
        response_data, timestamp = cache[key]
        if time.time() - timestamp < CACHE_EXPIRATION:
            return response_data
    return None

def set_cached_response(key, response_data):
    cache = load_cache()
    cache[key] = (response_data, time.time())
    save_cache(cache)

@app.route('/api/data', methods=['GET'])
def get_data():
    key = request.args.get('key')
    cached_response = get_cached_response(key)
    
    if cached_response:
        return jsonify(cached_response)

    # Simulate an expensive API call
    response_data = {"data": "expensive data", "key": key}
    set_cached_response(key, response_data)
    
    return jsonify(response_data)

if __name__ == '__main__':
    app.run(debug=True)